#include<bits/stdc++.h>
using namespace std;
int n,op,a[1000010],tot;
bool check(int x)
{
    int sum=0;
    for(int i=n;i>1;i--)
    {
        if(a[i]>=x)
        {
            sum++;
        }
        else
        {
            sum--;
        }
        if(sum>=0)
        {
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%d%d",&n,&op);
    int max1=0;
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        max1=max(max1,a[i]);
    }
    int l=0,r=max1,best;
    while(l<=r)
    {
        int mid=(l+r)>>1;
        if(check(mid))
        {
            l=mid+1;
            best=mid;
        }
        else
        {
            r=mid-1;
        }
    }
    printf("%d\n",best);
    if(op==0)
    {
        return 0;
    }
    vector<int> ans;
    int sum=0;
    max1=-1;
    for(int i=n;i>1;i--)
    {
        a[i]=(a[i]>=best?1:-1);
        sum+=a[i];
        if(sum>max1)
        {
            max1=sum;
            ans.push_back(i);
        }
    }
    reverse(ans.begin(),ans.end());
    printf("%d\n",ans.size());
    for(int i:ans)
    {
        printf("%d ",i);
    }
    return 0;
}
